		ManagerNeeded:       false,
		ContinuationStarted: true,
		ChildID:             source.ID,
		DeliveryID:          intent.DeliveryID,
		Result:              childCompletionResult(parsed.Result),
		NextChild:           nextChildInfoFromIntent(intent),
